if exists(select * from @@table where &Contract.Nested.Key.a;) begin select 'ma_hd' as field, replace(@$exists, '%s', rtrim(@ma_hd)) as message return end
&UnitBeforeInsert;
select @datetime0 = getdate(), @datetime2 = getdate(), @user_id0 = @@userID, @user_id2 = @@userID
&PaymentContractDirCommandInserting;

if not exists(select * from @@table where ma_hd = $ma_hd.OldValue) begin select 'ma_hd' as field, replace(@$recordHasBeenChanged, '%s', rtrim($ma_hd.OldValue)) as message return end
if @ma_hd <> $ma_hd.OldValue begin if exists(select * from @@table where &Contract.Nested.Key.a; and ma_hd <> $ma_hd.OldValue) begin select 'ma_hd' as field, replace(@$exists, '%s', rtrim(@ma_hd)) as message return end
declare @message nvarchar(255) select @message = replace(@$updateConflict, '%s', rtrim($ma_hd.OldValue)) if exists(select * from cdhd where ma_hd = $ma_hd.OldValue) begin select 'ma_hd' as field, @message as message return end if exists(select * from ct00 where ma_hd = $ma_hd.OldValue) begin select 'ma_hd' as field, @message as message return end
&PaymentContractDirCommandUpdatingUpdatePayment;
end
&PaymentContractDirCommandUpdatingDeletePayment; &UnitBeforeUpdate;


update @@table set datetime2 = getdate(), user_id2 = @@userID where ma_hd = @ma_hd

        &PaymentContractDirCommandUpdated;
