      &ScriptQueryData;

function onTabChanged&Identification;(sender, e) {
  var f = sender.parentForm;
&PaymentContractDirTabChanged;
}
function active$FormContract(f) {
  f.add_commandEvent(on$Voucher$ExecuteCommand);
  f.add_onResponseComplete(on$FormContract$ResponseComplete);
  f._tabContainer.add_activeTabChanged(onTabChanged&Identification;);
  f._tabContainer._loaded = true;
}
function close$FormContract(f) {
  if (f._tabContainer) try {f._tabContainer.remove_activeTabChanged(onTabChanged&Identification;);} catch (ex) {}
  try {f.remove_onResponseComplete(on$FormContract$ResponseComplete)} catch (ex) {}
  try {f.remove_commandEvent(on$Voucher$ExecuteCommand);} catch (ex) {}
}
/* <flatten type="Javascript"> */
function on$FormContract$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      objectBehavior$Dir$Irregular.checkCode(f, 'ma_hd');
      break;
    default:
      break;
  }
}
/* </flatten> */
function on$Voucher$ExecuteCommand(sender, e) {
  var action = e.type.Action, f = sender;
  &PaymentContractDirExecuteCommandDeclare;
  switch (action)	{
    case 'Gather':
    &PaymentContractDirExecuteCommandGather;
      break;
    default:
      break;
  }
}

